def _quicksort(arr, low, high):
    while low < high:
        mid = (low + high) // 2
        a, b, c = arr[low], arr[mid], arr[high]
        if a <= b <= c or c <= b <= a:
            arr[mid], arr[high] = arr[high], arr[mid]
        elif a <= c <= b or b <= c <= a:
            pass
        else:
            arr[low], arr[high] = arr[high], arr[low]
        pivot = arr[high]
        i = low - 1
        for j in range(low, high):
            if arr[j] <= pivot:
                i += 1
                arr[i], arr[j] = arr[j], arr[i]
        arr[i + 1], arr[high] = arr[high], arr[i + 1]
        p = i + 1
        if p - low < high - p:
            _quicksort(arr, low, p - 1)
            low = p + 1
        else:
            _quicksort(arr, p + 1, high)
            high = p - 1

def fast_sort(arr):
    if len(arr) <= 1:
        return list(arr)
    result = list(arr)
    n = len(result)
    width = 1
    tmp = [0] * n
    while width < n:
        for i in range(0, n, 2 * width):
            left = i
            mid = min(i + width, n)
            right = min(i + 2 * width, n)
            l, r, k = left, mid, left
            while l < mid and r < right:
                if result[l] <= result[r]:
                    tmp[k] = result[l]
                    l += 1
                else:
                    tmp[k] = result[r]
                    r += 1
                k += 1
            while l < mid:
                tmp[k] = result[l]
                l += 1
                k += 1
            while r < right:
                tmp[k] = result[r]
                r += 1
                k += 1
        result, tmp = tmp, result
        width *= 2
    return result

def fast_sort(arr):
    arr = list(arr)
    n = len(arr)
    if n <= 1:
        return arr
    for i in range(n // 2 - 1, -1, -1):
        _sift_down(arr, i, n)
    for end in range(n - 1, 0, -1):
        arr[0], arr[end] = arr[end], arr[0]
        _sift_down(arr, 0, end)
    return arr

def _sift_down(arr, start, end):
    root = start
    while True:
        child = 2 * root + 1
        if child >= end:
            break
        if child + 1 < end and arr[child] < arr[child + 1]:
            child += 1
        if arr[root] < arr[child]:
            arr[root], arr[child] = arr[child], arr[root]
            root = child
        else:
            break

