def _qsort(arr, lo, hi):
    if lo >= hi:
        return
    pivot = arr[hi]
    i = lo
    for j in range(lo, hi):
        if arr[j] < pivot:
            arr[i], arr[j] = arr[j], arr[i]
            i += 1
    arr[i], arr[hi] = arr[hi], arr[i]
    _qsort(arr, lo, i - 1)
    _qsort(arr, i + 1, hi)

def fast_sort(arr):
    if not arr:
        return []
    arr = list(arr)
    min_val = min(arr)
    if min_val < 0:
        arr = [x - min_val for x in arr]
    else:
        min_val = 0
    max_val = max(arr)
    if max_val == 0:
        return [min_val] * len(arr)
    num_digits = len(str(max_val))
    exp = 1
    for _ in range(num_digits):
        buckets = [[] for _ in range(10)]
        for num in arr:
            digit = (num // exp) % 10
            buckets[digit].append(num)
        arr = []
        for bucket in buckets:
            arr.extend(bucket)
        exp *= 10
    if min_val != 0:
        arr = [x + min_val for x in arr]
    return arr

